function statusBadge(s) {
  const map = {
    running:'green', healthy:'green', completed:'green', success:'green',
    pending:'yellow', waiting:'yellow', idle:'gray',
    failed:'red', error:'red', crashed:'red',
  };
  const cls = map[s?.toLowerCase()]  'gray';
  return `<span class="badge badge-${cls}">${s'—'}</span>`;
}

// ── Event Feed ───────────────────────────────────────────────────────────────
function evClass(type) {
  if (!type) return 'ev-system';
  if (type.includes('agent')) return 'ev-agent';
  if (type.includes('task')) return 'ev-task';
  if (type.includes('error')  type.includes('fail')) return 'ev-error';
  if (type.includes('tool')) return 'ev-tool';
  if (type.includes('pipeline')  type.includes('workflow')) return 'ev-bus';
  return 'ev-system';
}

function renderEvent(ev) {
  const t = timeStr(ev.timestamp);
  const type = ev.type  'unknown';
  const data = ev.data ? JSON.stringify(ev.data).slice(0,80) : '';
  return `<div class="event-line">
    <span class="ev-time">${t}</span>
    <span class="ev-type ${evClass(type)}">${type}</span>
    <span class="ev-data">${data}</span>
  </div>`;
}

function addToFeed(ev) {
  feedEvents.unshift(ev);
  if (feedEvents.length > MAX_FEED) feedEvents.pop();
  const feed = document.getElementById('feed');
  feed.innerHTML = feedEvents.map(renderEvent).join('');
}

function connectSSE() {
  const feed = document.getElementById('feed');
  const dot = document.getElementById('feedDot');
  const status = document.getElementById('connStatus');

  const es = new EventSource(`${API}/events`);

  es.onopen = () => {
    dot.className = 'dot dot-green';
    status.textContent = '● online';
    status.style.color = '#3fb950';
    feed.innerHTML = '';
  };

  es.onmessage = (e) => {
    try { addToFeed(JSON.parse(e.data)); } catch {}
  };

  es.onerror = () => {
    dot.className = 'dot dot-gray';
    status.textContent = '● offline';
    status.style.color = '#f85149';
    feed.innerHTML = '<div class="feed-status">Feed desligado. A reconectar…</div>';
    es.close();
    setTimeout(connectSSE, 5000);
  };
}

// ── Data Polling ─────────────────────────────────────────────────────────────
async function loadData() {
  try {
    const [agents, tasks, metrics, costs, routing] = await Promise.all([
      fetch(`${API}/agents`).then(r=>r.json()).catch(()=>({})),
      fetch(`${API}/tasks`).then(r=>r.json()).catch(()=>({})),
      fetch(`${API}/metrics`).then(r=>r.json()).catch(()=>({})),
      fetch(`${API}/costs`).then(r=>r.json()).catch(()=>({})),
      fetch(`${API}/routing`).then(r=>r.json()).catch(()=>({})),
    ]);

    // KPIs
    document.getElementById('kAgents').textContent = fmt(agents.total);
    const active = (agents.agents[]).filter(a=>a.status==='running').length;
    document.getElementById('kAgentsActive').textContent = ${active} activos;
    document.getElementById('kTasks').textContent = fmt(tasks.total);
    const pending = (tasks.tasks||[]).filter(t=>['pending','running'].includes(t.status)).length;
    document.getElementById('kTasksPending').textContent = ${pending} pendentes;
    document.getElementById('kSuccess').textContent = (metrics.success_rate ?? 100) + '%';
    const cost = costs.realtime_cost_usd ?? costs.total_cost_usd ?? 0;
    document.getElementById('kCost').textContent = fmtCost(cost);
    const tokens = metrics.token_usage?.total ?? 0;
    document.getElementById('kTokens').textContent = ${fmtNum(tokens)} tokens;

    // Routing bar
    const pctLocal = routing.pct_local ?? 0;
    document.getElementById('rLocal').textContent = pctLocal + '%';
    document.getElementById('rBar').style.width = pctLocal + '%';
    document.getElementById('rLocalCalls').textContent = ${fmtNum(routing.local_calls)} local;
    document.getElementById('rCloudCalls').textContent = ${fmtNum(routing.cloud_calls)} cloud;
    document.getElementById('rSavings').textContent = (routing.estimated_savings_pct ?? 0) + '%';

// Agents table
    const agTbody = document.querySelector('#agentsTable tbody');
    const agList = agents.agents  [];
    agTbody.innerHTML = agList.length
      ? agList.map(a => `<tr>
          <td style="font-weight:500">${a.name||a.id}</td>
          <td><span style="color:#8b949e">${a.role'—'}</span></td>
          <td>${statusBadge(a.status)}</td>
        </tr>`).join('')
      : <tr><td colspan="3" class="empty">Sem agentes</td></tr>;

    // Tasks table
    const tkTbody = document.querySelector('#tasksTable tbody');
    const tkList = (tasks.tasks  []).slice(0, 15);
    tkTbody.innerHTML = tkList.length
      ? tkList.map(t => `<tr>
          <td style="max-width:320px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${t.title||t.id}</td>
          <td>${statusBadge(t.status)}</td>
          <td style="color:#8b949e">${t.assigned_to'—'}</td>
          <td><span style="color:#8b949e">${t.priority??'—'}</span></td>
        </tr>`).join('')
      : <tr><td colspan="4" class="empty">Sem tarefas</td></tr>;

    document.getElementById('lastUpdate').textContent = new Date().toLocaleTimeString('pt');
  } catch(e) { console.error('[Dashboard]', e); }
}

// ── Init ─────────────────────────────────────────────────────────────────────
connectSSE();
loadData();
setInterval(loadData, 5000);
</script>
</body>
</html>
